/**
 * @summary Listar índices em cache
 */
export const getListIndexesUrl = (params?: ListIndexesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/indexes?${stringifiedParams}`
    : `/api/indexes`;
};

export const listIndexes = async (
  params?: ListIndexesParams,
  options?: RequestInit,
): Promise<IndexListResponse> => {
  return customFetch<IndexListResponse>(getListIndexesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListIndexesQueryKey = (params?: ListIndexesParams) => {
  return [`/api/indexes`, ...(params ? [params] : [])] as const;
};

export const getListIndexesQueryOptions = <
  TData = Awaited<ReturnType<typeof listIndexes>>,
  TError = ErrorType<unknown>,
>(
  params?: ListIndexesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listIndexes>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListIndexesQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listIndexes>>> = ({
    signal,
  }) => listIndexes(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listIndexes>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

