/**
 * @summary Sincronizar índices com IBGE/BCB
 */
export const getSyncIndexesUrl = () => {
  return `/api/indexes/sync`;
};

export const syncIndexes = async (
  syncIndexesInput: SyncIndexesInput,
  options?: RequestInit,
): Promise<SyncIndexesResponse> => {
  return customFetch<SyncIndexesResponse>(getSyncIndexesUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(syncIndexesInput),
  });
};

export const getSyncIndexesMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof syncIndexes>>,
    TError,
    { data: BodyType<SyncIndexesInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof syncIndexes>>,
  TError,
  { data: BodyType<SyncIndexesInput> },
  TContext
> => {
  const mutationKey = ["syncIndexes"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof syncIndexes>>,
    { data: BodyType<SyncIndexesInput> }
  > = (props) => {
    const { data } = props ?? {};

    return syncIndexes(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SyncIndexesMutationResult = NonNullable<
  Awaited<ReturnType<typeof syncIndexes>>
>;
export type SyncIndexesMutationBody = BodyType<SyncIndexesInput>;
export type SyncIndexesMutationError = ErrorType<unknown>;

/**
 * @summary Sincronizar índices com IBGE/BCB
 */
export const useSyncIndexes = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof syncIndexes>>,
    TError,
    { data: BodyType<SyncIndexesInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof syncIndexes>>,
  TError,
  { data: BodyType<SyncIndexesInput> },
  TContext
> => {
  return useMutation(getSyncIndexesMutationOptions(options));
};
